import React from 'react';
import { Link } from 'react-router-dom';

const Footer = () => {
  const styles = {
    footer: {
      background: '#1f2937',
      color: 'white',
      padding: '3rem 2rem 1rem',
      marginTop: '4rem'
    },
    container: {
      maxWidth: '1200px',
      margin: '0 auto',
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
      gap: '2rem'
    },
    section: {
      marginBottom: '1.5rem'
    },
    title: {
      color: '#4f46e5',
      marginBottom: '1rem',
      fontSize: '1.2rem'
    },
    link: {
      color: '#9ca3af',
      textDecoration: 'none',
      display: 'block',
      marginBottom: '0.5rem',
      transition: 'color 0.3s'
    },
    bottom: {
      textAlign: 'center',
      paddingTop: '2rem',
      marginTop: '2rem',
      borderTop: '1px solid #374151',
      color: '#9ca3af'
    }
  };

  return (
    <footer style={styles.footer}>
      <div style={styles.container}>
        <div style={styles.section}>
          <h3 style={styles.title}>Study Portal</h3>
          <p style={{ color: '#9ca3af', lineHeight: '1.6' }}>
            Your one-stop destination for notes, PYQs, syllabus and study materials.
          </p>
        </div>

        <div style={styles.section}>
          <h3 style={styles.title}>Quick Links</h3>
          <Link to="/" style={styles.link}>Home</Link>
          <Link to="/courses" style={styles.link}>Courses</Link>
          <Link to="/about" style={styles.link}>About</Link>
          <Link to="/contact" style={styles.link}>Contact</Link>
        </div>

        <div style={styles.section}>
          <h3 style={styles.title}>Resources</h3>
          <Link to="/notes" style={styles.link}>Notes</Link>
          <Link to="/pyqs" style={styles.link}>PYQs</Link>
          <Link to="/syllabus" style={styles.link}>Syllabus</Link>
          <Link to="/upload" style={styles.link}>Upload</Link>
        </div>

        <div style={styles.section}>
          <h3 style={styles.title}>Contact</h3>
          <p style={{ color: '#9ca3af', marginBottom: '0.5rem' }}>📧 studyportal@gmail.com</p>
          <p style={{ color: '#9ca3af', marginBottom: '0.5rem' }}>📞 +91 98765 43210</p>
          <p style={{ color: '#9ca3af' }}>📍 Delhi, India</p>
        </div>
      </div>

      <div style={styles.bottom}>
        <p>© 2024 Study Portal. All rights reserved.</p>
      </div>
    </footer>
  );
};

export default Footer;
